parameters.functionCode:
// Guard: si pas d'items (Text Classifier n'a rien approuve), on s'arrete
const items = $input.all();
if (!items || items.length === 0) return [];

// Recuperer le post depuis l'input direct
const inputJson = items[0].json;
const post = inputJson.post || '';

if (!post) return [];

const typeMatch = post.match(/\[TYPE:\s*(.+?)\]/);
const postType = typeMatch ? typeMatch[1].trim() : 'Concrete result';
const metrics = {
  currency: post.match(/\u20ac\s*\d+(?:[.,]\d+)?|\d+(?:[.,]\d+)?\s*\u20ac/gi) || [],
  times: post.match(/\d+\s*(?:h|min|hours?|days?|weeks?)/gi) || [],
  percentages: post.match(/\d+\s*%/gi) || [],
  numbers: post.match(/\d+(?:\s*(?:leads?|conversions?|people|users?))?/gi) || []
};
const all = [...metrics.currency,...metrics.times,...metrics.percentages,...metrics.numbers].slice(0,4);
return [{json:{postType,extractedMetrics:all,fullPost:post}}];

