={{ (function(){
const t=$json.postType,m=$json.extractedMetrics||[];
const L={'Concrete result':['Leads','Conversion','Time Saved','Revenue'],'Architecture':['Tools','Webhooks','Automations','Status'],'Optimization':['Original','Optimized','Gain','Status'],'Proof-based':['Executions','Success Rate','Avg Speed','Last Run']};
const lbl=L[t]||L['Concrete result'];
const mh=m.slice(0,4).map((v,i)=>`<div class="metric"><div class="metric-value">${v}</div><div class="metric-label">${lbl[i]||'Metric'}</div></div>`).join('');
return `<!DOCTYPE html><html><head><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',sans-serif;height:630px;width:1200px}.container{height:100%;display:flex;background:linear-gradient(135deg,#667eea,#764ba2);color:#fff;padding:40px}.content{flex:1;display:flex;flex-direction:column;justify-content:center}h1{font-size:48px;margin-bottom:10px;font-weight:700}.badge{font-size:14px;opacity:.85;margin-bottom:30px;background:rgba(255,255,255,.15);width:fit-content;padding:6px 12px;border-radius:4px}.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:20px}.metric{background:rgba(255,255,255,.1);padding:25px;border-radius:12px;text-align:center}.metric-value{font-size:38px;font-weight:700;margin-bottom:8px}.metric-label{font-size:13px;opacity:.85;text-transform:uppercase;letter-spacing:.5px}</style></head><body><div class="container"><div class="content"><h1>Automation Impact</h1><div class="badge">${t}</div><div class="metrics">${mh}</div></div></div></body></html>`;
